import React, { useState } from 'react';
import VirtualTable, { Operate, Layout } from 'react-tablex';

const columns = [
  {
    label: '序号',
    fieldkey: 'index',
    width: 80,
    custom: VirtualTable.VirtualNo,
  },
  {
    label: '内容',
    fieldkey: 'type',
    require: true,
    rules: [{ required: true, message: '必填' }],
    type: 'Input',
  },
];

const Demo = () => {
  const [dateSource, setDataSource] = useState([
    { type: '内容1' },
    { type: '内容2' },
  ]);

  const onChange = value => {
    setDataSource(value);
  };

  return (
    <VirtualTable
      columns={columns}
      value={dateSource}
      onChange={onChange}
      operateItems={[
        { type: Operate.Add },
        { type: Operate.Del },
        { type: Operate.MoveUp },
        { type: Operate.MoveDown },
      ]}
      operateConfig={{ width: 50, layout: Layout.Vertical }}
    />
  );
};

export default Demo;
